2008 static Constant *getFPClassConstant(Type *Ty, FPClassTest Mask,
2009                                     bool IsCanonicalizing = false) {
2010   if (Mask == fcNone)
2011     return PoisonValue::get(Ty);
2012 
2013   if (Mask == fcPosZero)
